/// Walks the style inheritance chain to find `outline_level`.
/// Falls back to string-matching on style name/ID if no StyleCatalog is available.
/// Returns 1-6 (markdown heading levels).
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_document_resolve_heading_level(
    this: *const kreuzberg::extraction::docx::parser::Document,
    style_id: *const std::ffi::c_char,
) -> u8 {
    clear_last_error();
    if this.is_null() {
        set_last_error(1, "Null pointer passed for self");
        return 0;
    }
    // SAFETY: null check above guarantees this is a valid pointer.
    let obj = unsafe { &*this };
    if style_id.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'style_id'");
        return 0;
    }
    let style_id_rs = match unsafe { CStr::from_ptr(style_id) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'style_id'");
            return 0;
        }
    };
    let result = obj.resolve_heading_level(&style_id_rs);
    match result {
        Some(val) => val,
        None => 0,
    }
}

