/// Render the document as markdown.
///
/// When `inject_placeholders` is `true`, drawings that reference an image
/// emit `![alt](image)` placeholders. When `false` they are silently
/// skipped, which is useful when the caller only wants text.
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_document_to_markdown(
    this: *const kreuzberg::extraction::docx::parser::Document,
    inject_placeholders: i32,
) -> *mut std::ffi::c_char {
    clear_last_error();
    if this.is_null() {
        set_last_error(1, "Null pointer passed for self");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees this is a valid pointer.
    let obj = unsafe { &*this };
    let inject_placeholders_rs = inject_placeholders != 0;
    let result = obj.to_markdown(inject_placeholders_rs);
    match CString::new(result) {
        Ok(cs) => cs.into_raw(),
        Err(_) => std::ptr::null_mut(),
    }
}

