/// Resolve a style by walking its `basedOn` inheritance chain.
///
/// The resolution order is:
/// 1. Document defaults (`<w:docDefaults>`)
/// 2. Base style chain (walking `basedOn` from root to leaf)
/// 3. The style itself
///
/// For `Option` fields, a child value of `Some(x)` overrides the parent.
/// A value of `None` inherits from the parent. For boolean toggle properties,
/// `Some(false)` explicitly disables the property.
///
/// The chain depth is limited to 20 to prevent infinite loops from circular references.
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_style_catalog_resolve_style(
    this: *const kreuzberg::extraction::docx::styles::StyleCatalog,
    style_id: *const std::ffi::c_char,
) -> *mut kreuzberg::extraction::docx::styles::ResolvedStyle {
    clear_last_error();
    if this.is_null() {
        set_last_error(1, "Null pointer passed for self");
        return std::ptr::null_mut();
    }
    // SAFETY: null check above guarantees this is a valid pointer.
    let obj = unsafe { &*this };
    if style_id.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'style_id'");
        return std::ptr::null_mut();
    }
    let style_id_rs = match unsafe { CStr::from_ptr(style_id) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'style_id'");
            return std::ptr::null_mut();
        }
    };
    let result = obj.resolve_style(&style_id_rs);
    Box::into_raw(Box::new(result))
}

