/// Create an iterator from raw PDF bytes.
///
/// Validates the PDF and determines the page count. The PDF bytes are
/// owned by the iterator — the file is not re-read from disk.
///
/// # Errors
///
/// Returns an error if the PDF is invalid or password-protected without
/// the correct password.
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_pdf_page_iterator_new(
    pdf_bytes: *const u8,
    pdf_bytes_len: usize,
    dpi: i32,
    password: *const std::ffi::c_char,
) -> *mut kreuzberg::pdf::PdfPageIterator {
    clear_last_error();
    if pdf_bytes.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'pdf_bytes'");
        return std::ptr::null_mut();
    }
    let pdf_bytes_rs = unsafe { std::slice::from_raw_parts(pdf_bytes, pdf_bytes_len) }.to_vec();
    let dpi_rs = if dpi == i32::MAX { None } else { Some(dpi) };
    let password_rs = if password.is_null() {
        None
    } else {
        match unsafe { CStr::from_ptr(password) }.to_str() {
            Ok(s) => Some(s.to_string()),
            Err(_) => {
                set_last_error(1, "Invalid UTF-8 in parameter 'password'");
                return std::ptr::null_mut();
            }
        }
    };
    let result = kreuzberg::pdf::PdfPageIterator::new(&pdf_bytes_rs, dpi_rs, password_rs);
    match result {
        Ok(val) => Box::into_raw(Box::new(val.clone())),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

