/// Merge extraction configuration using JSON-level field override.
///
/// Serializes the base config to JSON, merges each field from the override JSON
/// (top-level only), and deserializes back. This correctly handles boolean fields
/// explicitly set to their default values — the override always wins for any field
/// present in `override_json`.
///
/// Fields **not** present in `override_json` are preserved from `base`.
///
/// # Errors
///
/// Returns `Err` if the base config cannot be serialized, or if the merged JSON
/// cannot be deserialized back into `ExtractionConfig` (e.g., wrong field types).
///
/// # Examples
///
/// ```rust,ignore
/// use kreuzberg::ExtractionConfig;
/// use serde_json::json;
///
/// let mut base = ExtractionConfig::default();
/// base.use_cache = true;
///
/// let overrides = json!({"force_ocr": true});
/// let merged = kreuzberg::core::config::merge::merge_config_json(&base, overrides).unwrap();
/// assert!(merged.use_cache);   // preserved from base
/// assert!(merged.force_ocr);   // applied from override
/// ```
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_merge_config_json(
    base: *const kreuzberg::ExtractionConfig,
    override_json: *const std::ffi::c_char,
) -> *mut kreuzberg::ExtractionConfig {
    clear_last_error();
    if base.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'base'");
        return std::ptr::null_mut();
    }
    let base_rs = unsafe { &*base }.clone();
    if override_json.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'override_json'");
        return std::ptr::null_mut();
    }
    let override_json_str = match unsafe { CStr::from_ptr(override_json) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'override_json'");
            return std::ptr::null_mut();
        }
    };
    let override_json_rs = match serde_json::from_str(override_json_str) {
        Ok(v) => v,
        Err(_) => {
            set_last_error(1, "Invalid JSON in parameter 'override_json'");
            return std::ptr::null_mut();
        }
    };
    let result = kreuzberg::core::config::merge::merge_config_json(&base_rs, override_json_rs);
    match result {
        Ok(val) => Box::into_raw(Box::new(val.clone())),
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

/// Build extraction config by optionally merging JSON overrides into a base config.
