/// Generate a unique element ID for semantic content.
///
/// Creates a deterministic hash-based ID from the element type, text content,
/// and page number. Uses a simple wrapping multiplication algorithm for
/// consistent ID generation without external dependencies.
///
/// # Arguments
///
/// * `text` - The element text content
/// * `element_type` - The semantic element type
/// * `page_number` - Optional page number for multi-page documents
///
/// # Returns
///
/// An ElementId suitable for referencing this semantic element
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_generate_element_id(
    text: *const std::ffi::c_char,
    element_type: *const kreuzberg::ElementType,
    page_number: usize,
) -> *mut kreuzberg::ElementId {
    clear_last_error();
    if text.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'text'");
        return std::ptr::null_mut();
    }
    let text_rs = match unsafe { CStr::from_ptr(text) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'text'");
            return std::ptr::null_mut();
        }
    };
    if element_type.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'element_type'");
        return std::ptr::null_mut();
    }
    let element_type_rs = unsafe { &*element_type }.clone();
    let page_number_rs = if page_number == usize::MAX {
        None
    } else {
        Some(page_number)
    };
    let result = kreuzberg::extraction::generate_element_id(&text_rs, element_type_rs, page_number_rs);
    Box::into_raw(Box::new(result))
}

