/// Process extracted images with OCR if configured.
///
/// For each image, spawns a blocking OCR task and stores the result
/// in `image.ocr_result`. If OCR is not configured or fails for an
/// individual image, that image's `ocr_result` remains `None`.
///
/// This function is the single shared implementation used by all
/// document extractors (DOCX, PPTX, Jupyter, Markdown, etc.).
///
/// # Recursion Safety
///
/// The produced `ExtractionResult` for each image explicitly sets
/// `images: None`, preventing further image extraction cycles when
/// OCR results are consumed by archive or recursive extraction paths.
///
/// # Concurrency
///
/// Concurrency is bounded by the configured thread budget
/// using a semaphore to prevent resource exhaustion.
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_process_images_with_ocr(
    images: *const std::ffi::c_char,
    config: *const kreuzberg::ExtractionConfig,
) -> *mut std::ffi::c_char {
    clear_last_error();
    if images.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'images'");
        return std::ptr::null_mut();
    }
    let images_rs_str = match unsafe { CStr::from_ptr(images) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'images'");
            return std::ptr::null_mut();
        }
    };
    let images_rs = match serde_json::from_str(images_rs_str) {
        Ok(v) => v,
        Err(e) => {
            set_last_error(2, &e.to_string());
            return std::ptr::null_mut();
        }
    };
    if config.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'config'");
        return std::ptr::null_mut();
    }
    let config_rs = unsafe { &*config }.clone();
    let result = get_ffi_runtime()
        .block_on(async { kreuzberg::extraction::image_ocr::process_images_with_ocr(images_rs, &config_rs).await });
    match result {
        Ok(val) => match serde_json::to_string(&val) {
            Ok(s) => match CString::new(s) {
                Ok(cs) => cs.into_raw(),
                Err(_) => std::ptr::null_mut(),
            },
            Err(_) => std::ptr::null_mut(),
        },
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

