/// Read and Snappy-decompress a single `.iwa` file from the ZIP archive.
///
/// Apple IWA files use a custom framing format:
/// Each block in the file is: `[type: u8][length: u24 LE][payload: length bytes]`
/// - type `0x00`: Snappy-compressed block → decompress payload with raw Snappy
/// - type `0x01`: Uncompressed block → use payload as-is
///
/// Multiple blocks are concatenated to form the decompressed IWA stream.
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_read_iwa_file(
    content: *const u8,
    content_len: usize,
    path: *const std::ffi::c_char,
) -> *mut u8 {
    clear_last_error();
    if content.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'content'");
        return std::ptr::null_mut();
    }
    let content_rs = unsafe { std::slice::from_raw_parts(content, content_len) }.to_vec();
    if path.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'path'");
        return std::ptr::null_mut();
    }
    let path_rs = match unsafe { CStr::from_ptr(path) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'path'");
            return std::ptr::null_mut();
        }
    };
    let result = kreuzberg::extractors::iwork::read_iwa_file(&content_rs, &path_rs);
    match result {
        Ok(val) => val.as_ptr() as *mut u8,
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

/// Decode an Apple IWA byte stream into the raw protobuf payload.
