/// use kreuzberg::utils::pool_sizing::estimate_pool_size;
///
/// let hint = estimate_pool_size(5_000_000, "application/pdf");
/// // PDF at 5MB gets 10 string buffers (base 6 + 4 for size)
/// // of 65KB each (for 1-10MB files)
/// ```
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_estimate_pool_size(
    file_size: u64,
    mime_type: *const std::ffi::c_char,
) -> *mut kreuzberg::utils::PoolSizeHint {
    clear_last_error();
    let file_size_rs = file_size;
    if mime_type.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'mime_type'");
        return std::ptr::null_mut();
    }
    let mime_type_rs = match unsafe { CStr::from_ptr(mime_type) }.to_str() {
        Ok(s) => s.to_string(),
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'mime_type'");
            return std::ptr::null_mut();
        }
    };
    let result = kreuzberg::utils::estimate_pool_size(file_size_rs, &mime_type_rs);
    Box::into_raw(Box::new(result))
}

