/// Reconstruct a table grid from words with bounding box positions.
///
/// Takes detected words and reconstructs a 2D table by:
/// 1. Detecting column positions (grouping by x-coordinate within `column_threshold`)
/// 2. Detecting row positions (grouping by y-center within `row_threshold_ratio` * median height)
/// 3. Assigning words to cells based on closest row/column
/// 4. Combining words within the same cell
///
/// Returns a `Vec<Vec<String>>` where each inner `Vec` is a row of cell texts.
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_reconstruct_table(
    words: *const std::ffi::c_char,
    column_threshold: u32,
    row_threshold_ratio: f64,
) -> *mut std::ffi::c_char {
    clear_last_error();
    if words.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'words'");
        return std::ptr::null_mut();
    }
    let words_rs_str = match unsafe { CStr::from_ptr(words) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'words'");
            return std::ptr::null_mut();
        }
    };
    let words_rs = match serde_json::from_str(words_rs_str) {
        Ok(v) => v,
        Err(e) => {
            set_last_error(2, &e.to_string());
            return std::ptr::null_mut();
        }
    };
    let column_threshold_rs = column_threshold;
    let row_threshold_ratio_rs = row_threshold_ratio;
    let result = kreuzberg::table_core::reconstruct_table(words_rs, column_threshold_rs, row_threshold_ratio_rs);
    match serde_json::to_string(&result) {
        Ok(s) => match CString::new(s) {
            Ok(cs) => cs.into_raw(),
            Err(_) => std::ptr::null_mut(),
        },
        Err(_) => std::ptr::null_mut(),
    }
}

