pub unsafe extern "C" fn kreuzberg_merge_chars_into_blocks(chars: *const std::ffi::c_char) -> *mut std::ffi::c_char {
    clear_last_error();
    if chars.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'chars'");
        return std::ptr::null_mut();
    }
    let chars_rs_str = match unsafe { CStr::from_ptr(chars) }.to_str() {
        Ok(s) => s,
        Err(_) => {
            set_last_error(1, "Invalid UTF-8 in parameter 'chars'");
            return std::ptr::null_mut();
        }
    };
    let chars_rs = match serde_json::from_str(chars_rs_str) {
        Ok(v) => v,
        Err(e) => {
            set_last_error(2, &e.to_string());
            return std::ptr::null_mut();
        }
    };
    let result = kreuzberg::pdf::hierarchy::merge_chars_into_blocks(chars_rs);
    match serde_json::to_string(&result) {
        Ok(s) => match CString::new(s) {
            Ok(cs) => cs.into_raw(),
            Err(_) => std::ptr::null_mut(),
        },
        Err(_) => std::ptr::null_mut(),
    }
}

