/// Serialize an [`ExtractionResult`] to TOON (Token-Oriented Object Notation).
///
/// TOON is a token-efficient alternative to JSON for LLM prompts.
/// Losslessly convertible to/from JSON but uses fewer tokens.
/// # Safety
/// Caller must ensure all pointer arguments are valid or null.
/// Returned pointers must be freed with the appropriate free function.
#[unsafe(no_mangle)]
pub unsafe extern "C" fn kreuzberg_serialize_to_toon(
    result: *const kreuzberg::ExtractionResult,
) -> *mut std::ffi::c_char {
    clear_last_error();
    if result.is_null() {
        set_last_error(1, "Null pointer passed for parameter 'result'");
        return std::ptr::null_mut();
    }
    let result_rs = unsafe { &*result }.clone();
    let result = kreuzberg::serialize_to_toon(&result_rs);
    match result {
        Ok(val) => match CString::new(val.to_string()) {
            Ok(cs) => cs.into_raw(),
            Err(_) => std::ptr::null_mut(),
        },
        Err(e) => {
            set_last_error(2, &e.to_string());
            std::ptr::null_mut()
        }
    }
}

